// =====================================================================
// config.js — PRODUCTION Configuration
// Upload this as External JS #2 in Cognition.run (after plugin-loader.js)
// =====================================================================
// 
// PRODUCTION VERSION: Uses Cognition.run's automatic condition assignment
// Cognition provides global variable CONDITION (1 or 2) based on your
// "Inter experiment conditions" setting (set to 2 in Cognition config).
// Participants are automatically distributed equally across conditions.
//
// =====================================================================

// Map Cognition's CONDITION number to condition name
// CONDITION 1 → shared_paths
// CONDITION 2 → vanilla_paths
var CONDITION_MAP = {
  1: "shared_paths",
  2: "vanilla_paths"
};

// Get condition from Cognition's global CONDITION variable
// (defaults to 1 if not available, e.g., when testing locally)
var assignedCondition = (typeof CONDITION !== 'undefined') ? CONDITION : 1;

var CONFIG = {
  // Target letters for detection task
  targetLetters: ["S", "X"],
  
  // Condition: Automatically set from Cognition's CONDITION variable
  // "shared_paths" or "vanilla_paths"  
  condition: CONDITION_MAP[assignedCondition] || "shared_paths",
  
  // The raw Cognition condition number (1 or 2)
  conditionNumber: assignedCondition,
  
  // Number of stimuli per letter (set to 0 to use ALL available)
  // With 0: 100 actual pairs (200 videos) + 10 practice pairs (20 videos)
  nActual: 0,
  nPractice: 0,
  
  // UI settings
  continueKey: "k"
};

